+/// Create a mock XL device info for testing.
+fn mock_device_xl() -> DeviceInfo {
+    DeviceInfo {
+        serial: "AL12XL0001".to_string(),
+        product_name: "Stream Deck XL".to_string(),
+        firmware_version: "1.5.3".to_string(),
+        key_count: 32,
+        key_width: 96,
+        key_height: 96,
+        rows: 4,
+        cols: 8,
+        kind: "Xl".to_string(),
+    }
+}
