+fn button_event_fields_use_snake_case() {
+    let event = ButtonEvent {
+        key: 0,
+        pressed: true,
+        timestamp_ms: 1000,
+    };
+    let json = serde_json::to_value(&event).expect("serialize");
+    let obj = json.as_object().unwrap();
+
+    for key in obj.keys() {
+        assert!(
+            !key.chars().any(|c| c.is_uppercase()),
+            "Field '{key}' should use snake_case"
+        );
+    }
+}
